"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["63329"],{23689(e){e.exports=JSON.parse('{"tag":{"label":"gamedev","permalink":"/sysanalyst-kb.github.io/tech/tags/gamedev","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":4,"items":[{"id":"appsflyer","title":"AppsFlyer / Adjust \u2014 mobile attribution \u0438 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"AppsFlyer \u0438 Adjust \u2014 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B mobile-\u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438 \u0438 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0438. \u041E\u043D\u0438 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044E\u0442 \u043E\u0442\u043A\u0443\u0434\u0430 \u043F\u0440\u0438\u0448\u0451\u043B \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C (\u043A\u0430\u043A\u0430\u044F \u0440\u0435\u043A\u043B\u0430\u043C\u0430 \u043F\u0440\u0438\u0432\u0435\u043B\u0430 \u043A \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0435), \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u044E\u0442 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u0441 \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u044B\u043C\u0438 \u043A\u0430\u043C\u043F\u0430\u043D\u0438\u044F\u043C\u0438 \u0438 \u043F\u0435\u0440\u0435\u0434\u0430\u044E\u0442 \u0434\u0430\u043D\u043D\u044B\u0435 \u0432 ad networks \u0434\u043B\u044F \u043E\u043F\u0442\u0438\u043C\u0438\u0437\u0430\u0446\u0438\u0438. \u0412 \u044D\u043F\u043E\u0445\u0443 Apple SKAdNetwork \u0438 ATT (App Tracking Transparency) \u0440\u043E\u043B\u044C \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438 \u043A\u0430\u0440\u0434\u0438\u043D\u0430\u043B\u044C\u043D\u043E \u0438\u0437\u043C\u0435\u043D\u0438\u043B\u0430\u0441\u044C: \u0434\u0435\u0442\u0435\u0440\u043C\u0438\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u044F (\u043F\u043E IDFA) \u0443\u0441\u0442\u0443\u043F\u0438\u043B\u0430 \u043C\u0435\u0441\u0442\u043E \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0441\u0442\u043D\u043E\u0439 (probabilistic) \u0438 SKAdNetwork. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 in-app events (\u043F\u043E\u043A\u0443\u043F\u043A\u0438, \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F), postback-\u043A\u043E\u043B\u0431\u0435\u043A\u0438 \u0434\u043B\u044F ad networks, \u043A\u043E\u0433\u043E\u0440\u0442\u043D\u044B\u0435 \u043E\u0442\u0447\u0451\u0442\u044B \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 DWH.","permalink":"/sysanalyst-kb.github.io/tech/appsflyer"},{"id":"firebase","title":"Firebase \u2014 \u044D\u043A\u043E\u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u043B\u044F \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u044B\u0445 \u0438\u0433\u0440","description":"Firebase (Google) \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u0435-\u0444\u0430\u043A\u0442\u043E \u0434\u043B\u044F \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u044B\u0445 \u0438\u0433\u0440. \u041D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430, \u0430 \u0446\u0435\u043B\u0430\u044F \u044D\u043A\u043E\u0441\u0438\u0441\u0442\u0435\u043C\u0430: Analytics, Crashlytics, Remote Config, Cloud Messaging (Push), Performance Monitoring, Cloud Firestore, Authentication \u0438 A/B Testing. Firebase \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u0442 80% \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0435\u0439 \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u043E\u0439 \u0438\u0433\u0440\u044B \u0431\u0435\u0437 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0431\u044D\u043A\u0435\u043D\u0434\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0441\u043E\u0431\u044B\u0442\u0438\u044F (event tracking), Remote Config \u0434\u043B\u044F A/B \u0442\u0435\u0441\u0442\u043E\u0432, Crashlytics \u0434\u043B\u044F \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433\u0430 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 BigQuery \u0434\u043B\u044F \u0441\u044B\u0440\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445.","permalink":"/sysanalyst-kb.github.io/tech/firebase"},{"id":"photon","title":"Photon / Netcode \u2014 \u043C\u0443\u043B\u044C\u0442\u0438\u043F\u043B\u0435\u0435\u0440","description":"\u0421\u0435\u0442\u0435\u0432\u043E\u0439 \u043C\u0443\u043B\u044C\u0442\u0438\u043F\u043B\u0435\u0435\u0440 \u0432 \u0438\u0433\u0440\u0430\u0445 \u2014 \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447. Photon (Exit Games) \u2014 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u043E\u0435 \u0433\u043E\u0442\u043E\u0432\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 Unity Netcode for GameObjects, Mirror (open-source), Nakama (Heroic Labs), Colyseus (JS), \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0435\u0440\u0432\u0435\u0440\u043D\u044B\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438. \u0412\u044B\u0431\u043E\u0440 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0438 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u0442\u0438\u043F\u0430 \u0438\u0433\u0440\u044B: \u0434\u043B\u044F \u043A\u0430\u0437\u0443\u0430\u043B\u044C\u043D\u043E\u0433\u043E PvP \u0445\u0432\u0430\u0442\u0438\u0442 PUN, \u0434\u043B\u044F \u0441\u043E\u0440\u0435\u0432\u043D\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u2014 \u043D\u0443\u0436\u0435\u043D Quantum \u0441 \u0434\u0435\u0442\u0435\u0440\u043C\u0438\u043D\u0438\u0437\u043C\u043E\u043C, \u0434\u043B\u044F MMO \u2014 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0441\u0435\u0440\u0432\u0435\u0440 \u043D\u0430 C++/Rust. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442 \u0442\u0438\u043F \u0441\u0438\u043D\u0445\u0440\u043E\u043D\u0438\u0437\u0430\u0446\u0438\u0438 (authoritative vs peer-to-peer), \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 API \u0441\u0435\u0441\u0441\u0438\u0438 \u0438 \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C \u043C\u0430\u0442\u0447\u0430.","permalink":"/sysanalyst-kb.github.io/tech/photon"},{"id":"unity","title":"Unity / Unreal Engine \u2014 \u0438\u0433\u0440\u043E\u0432\u044B\u0435 \u0434\u0432\u0438\u0436\u043A\u0438","description":"Unity \u0438 Unreal Engine \u2014 \u0434\u0432\u0430 \u0434\u043E\u043C\u0438\u043D\u0438\u0440\u0443\u044E\u0449\u0438\u0445 \u0438\u0433\u0440\u043E\u0432\u044B\u0445 \u0434\u0432\u0438\u0436\u043A\u0430. Unity (C#, .NET) \u2014 \u043B\u0438\u0434\u0435\u0440 \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u044B\u0445 \u0438 \u043A\u0430\u0437\u0443\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0433\u0440, \u0432\u044B\u0431\u043E\u0440 \u0434\u043B\u044F \u0441\u0442\u0430\u0440\u0442\u0430\u043F\u043E\u0432. Unreal Engine (C++, Blueprints) \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 AAA-\u0438\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u0438 (\u041F\u041A/\u043A\u043E\u043D\u0441\u043E\u043B\u0438). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0443 \u0432\u0430\u0436\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0434\u0432\u0438\u0436\u043A\u0430: \u0447\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u043D\u0430 \u043A\u043B\u0438\u0435\u043D\u0442\u0435, \u0447\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0441\u0435\u0440\u0432\u0435\u0440\u0430, \u043A\u0430\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0442 asset bundles, remote config \u0438 SDK-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0412\u044B\u0431\u043E\u0440 \u0434\u0432\u0438\u0436\u043A\u0430 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 \u0441\u0442\u0435\u043A \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0439, \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u044C \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438 \u0441\u043E\u0441\u0442\u0430\u0432 \u043A\u043E\u043C\u0430\u043D\u0434\u044B.","permalink":"/sysanalyst-kb.github.io/tech/unity"}],"unlisted":false}}')}}]);